import * as t from "io-ts";
import { AccountBaseBuildOptions } from "./accountBaseBuildOptions";
import { DotFeeOptions } from "./dotFeeOptions";
import { Optional } from "../../../utils";

export const DotAccountBaseBuildOptions = t.intersection([
  AccountBaseBuildOptions,
  t.partial({
    fee: Optional(DotFeeOptions),
  }),
]);

export type DotAccountBaseBuildOptions = t.TypeOf<
  typeof DotAccountBaseBuildOptions
>;
